import{_ as e,o as t,c as o,a2 as s}from"./chunks/framework.DCVnL8g5.js";const u=JSON.parse('{"title":"Integracion con frameworks","description":"","frontmatter":{},"headers":[],"relativePath":"full-stack/arquitectura/hexagonal/09-integracion-con-frameworks.md","filePath":"full-stack/arquitectura/hexagonal/09-integracion-con-frameworks.md","lastUpdated":1782521464000}'),n={name:"full-stack/arquitectura/hexagonal/09-integracion-con-frameworks.md"};function i(r,a,l,c,d,p){return t(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="integracion-con-frameworks" tabindex="-1">Integracion con frameworks <a class="header-anchor" href="#integracion-con-frameworks" aria-label="Permalink to &quot;Integracion con frameworks&quot;">​</a></h1><p>La arquitectura hexagonal no esta renida con frameworks. El punto es usarlos en los bordes, no en el nucleo.</p><h2 id="spring-boot" tabindex="-1">Spring Boot <a class="header-anchor" href="#spring-boot" aria-label="Permalink to &quot;Spring Boot&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>@RestController -&gt; use case -&gt; repository port -&gt; @Repository adapter</span></span></code></pre></div><p>Las anotaciones de Spring deben quedarse fuera del dominio.</p><h2 id="nestjs" tabindex="-1">NestJS <a class="header-anchor" href="#nestjs" aria-label="Permalink to &quot;NestJS&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller -&gt; Injectable use case -&gt; provider token -&gt; adapter</span></span></code></pre></div><p>Los modulos de Nest pueden envolver modulos de negocio, pero no sustituir el modelo.</p><h2 id="fastapi" tabindex="-1">FastAPI <a class="header-anchor" href="#fastapi" aria-label="Permalink to &quot;FastAPI&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>router -&gt; dependency injection -&gt; use case -&gt; port</span></span></code></pre></div><p>Pydantic es excelente en el borde, pero el dominio no tiene por que ser un modelo Pydantic.</p><h2 id="django" tabindex="-1">Django <a class="header-anchor" href="#django" aria-label="Permalink to &quot;Django&quot;">​</a></h2><p>Django empuja hacia modelos activos. Para dominios complejos, puedes separar:</p><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Django View -&gt; use case -&gt; domain model -&gt; Django ORM adapter</span></span></code></pre></div><h2 id="laravel" tabindex="-1">Laravel <a class="header-anchor" href="#laravel" aria-label="Permalink to &quot;Laravel&quot;">​</a></h2><div class="language-txt vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Controller -&gt; Action/UseCase -&gt; Repository contract -&gt; Eloquent adapter</span></span></code></pre></div><p>Eloquent puede vivir como adaptador de persistencia.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><ul><li>El framework arranca y cablea.</li><li>Los controladores son adaptadores.</li><li>Los modelos de ORM no invaden el dominio si hay reglas complejas.</li><li>La inyeccion de dependencias conecta puertos y adaptadores.</li><li>Los tests del nucleo no arrancan el framework.</li></ul>',19)])])}const g=e(n,[["render",i]]);export{u as __pageData,g as default};
